using Forge.Core.Entities;
using Forge.Core.Enums;
using Forge.Data.Context;

using Serilog;

namespace Forge.Api.Data.TrainingContent;

public class BacklogTraining : TrainingContentBase
{
    public BacklogTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Backlog Overview",
            Slug = "backlog-overview",
            Summary = "What the backlog is, how it relates to the kanban board, filtering jobs, view modes, and creating new jobs.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/backlog"]""",
            Tags = """["backlog","jobs","kanban"]""",
            ContentJson = """{"body":"## Backlog Overview\n\nThe Backlog is your master list of all jobs across every track type. While the Kanban Board gives you a visual, stage-by-stage view of a single track, the Backlog lets you see every job in the system at once — search, filter, sort, and triage work before it hits the board.\n\n### Backlog vs. Kanban Board\n\nThe Kanban Board shows jobs organized into columns by stage within a single track type (e.g., Production, R&D/Tooling, Maintenance). You interact with jobs visually — dragging cards between stages, seeing WIP limits, and tracking flow.\n\nThe Backlog is a flat list of all jobs regardless of track type. It is the place to:\n- **Find any job** by number, title, customer, or assignee\n- **Triage incoming work** — review unassigned or low-priority jobs\n- **Bulk review** — scan across tracks to spot overdue items, unbalanced workloads, or stalled jobs\n- **Create new jobs** that land on the board in their track's first stage\n\nEvery job in the Backlog also appears on its corresponding Kanban Board. Changes made in either place are reflected in both.\n\n### Two View Modes\n\nThe Backlog offers two ways to look at your jobs:\n\n**Table View (default)** — A data table with sortable, filterable columns: Job Number, Title, Stage, Priority, Assignee, Customer, and Due Date. Click any column header to sort. Use the column filter icons for per-column filtering (text search, enum selection, or date range). Click any row to open the full job detail dialog.\n\n**Card View** — A grid of job cards showing the job number, title, stage chip (color-coded), priority dot, assignee avatar, customer name, and due date. Cards with active holds show an 'On Hold' badge. Overdue cards are visually highlighted. Click any card to open the job detail dialog.\n\nToggle between views using the view icons in the page header (view_list for table, view_module for cards). Your preference is saved and restored on your next visit.\n\n### Filtering\n\nFour filters in the page header narrow down the list:\n\n- **Search** — free-text search across job number and title. Results update as you type.\n- **Track Type** — filter to a specific track (Production, R&D/Tooling, etc.). Shows only jobs whose current stage belongs to that track.\n- **Priority** — filter by Low, Normal, High, or Urgent.\n- **Assignee** — filter to jobs assigned to a specific team member.\n\nAll filters work together (AND logic). The filtered count is reflected in both table and card views.\n\n### Creating Jobs\n\nClick the 'Create Job' button (with the + icon) in the page header to open the job creation dialog. You will enter:\n\n- **Title** (required, max 200 characters)\n- **Description** (optional, multi-line)\n- **Track Type** (required) — determines which board and initial stage the job enters\n- **Customer** (optional) — links the job to a customer record\n- **Assignee** (optional) — assigns a team member. If the selected user has an incomplete profile, a warning is shown.\n- **Priority** (defaults to Normal) — Low, Normal, High, or Urgent\n- **Due Date** (optional) — displayed in red when overdue\n\nThe new job is placed in the first stage of the selected track type and appears on both the Backlog and the Kanban Board immediately.\n\n### Job Detail\n\nClicking any row (table view) or card (card view) opens the full job detail dialog via the DetailDialogService. The URL updates to include `?detail=job:{id}`, making the link shareable and bookmarkable. From the detail dialog you can edit the job, view subtasks, files, activity log, and more.\n\n### Editing an Existing Job\n\nThere is no Edit button directly on the backlog row or card. To edit a job, open it first: click the row or card to open the job detail dialog, then use its **Edit** action. The detail dialog closes and the job re-opens in the same dialog you use to create jobs — but now in **edit mode** (the title reads 'Edit Job'). When you save, the list reloads and your changes appear.\n\nTwo things behave differently in edit mode versus create mode:\n- **Track Type is immutable.** The Track Type field is hidden entirely when editing. A job's track type is fixed at creation because it determines which Kanban board the job lives on — moving a job to a different board would orphan its stage history, so the system does not allow it. If a job is on the wrong track, archive it and create a replacement on the correct track.\n- **The Sales Order line association is create-only.** The field that links a new job to a sales-order line appears only in create mode and is hidden when editing.\n\nEverything else — Title, Description, Customer, Assignee, Priority, and Due Date — is editable. The save button reads 'Save Changes' instead of 'Create Job'.\n\n### Admin: Archived Jobs\n\nJobs are never hard-deleted — when a job is removed from a board it is **archived** (soft-deleted), so it disappears from the active backlog and board but is fully recoverable. Administrators get a recovery path right on the backlog.\n\n**Show Archived / Show Active toggle.** Admins see an extra icon button in the page header (an inventory-box icon). Click it to switch the list from active jobs to archived jobs; the tooltip and icon flip between 'Show archived jobs' and 'Show active jobs'. The list re-fetches from the server with the archived flag set, so you are looking at a genuinely separate set of jobs, not a client-side filter. Non-admins never see this toggle and cannot reach the archived view.\n\n**Row-level Unarchive.** In the archived view, the table gains an **Actions** column with an Unarchive button on each row. Clicking it asks you to confirm ('Restore this job?'), then restores that single job to the active list. Because the job is now active again, it drops out of the archived view on the next reload and reappears on its Kanban board.\n\n**Bulk Unarchive.** The archived table also becomes selectable: a checkbox appears on each row. Select one or more archived jobs and a bulk action bar slides up from the bottom showing the selected count and an **Unarchive selected** button. Confirm the prompt ('Restore selected jobs?') and all selected jobs are restored in one operation. A success message reports how many were restored. Use the X on the bulk bar to clear the selection without acting.\n\nBoth the toggle and the unarchive actions are Admin-only in the UI, and the server independently enforces the Admin role — restoring work that someone deliberately archived is high-impact, so it is deliberately gated.\n\n### Row Styling (Table View)\n\n- **Overdue rows** get the `row--overdue` class — a subtle red tint indicating the due date has passed.\n- **Selected row** gets the `row--selected` class — highlighted to show which job's detail is currently open.\n- **Stage color tint** — each row has a faint background tint matching its stage color via the `--row-tint` CSS custom property.\n\n### Priority Colors\n\nPriority is shown as a colored dot next to the priority name:\n- **Low** — slate gray (#94a3b8)\n- **Normal** — teal (#0d9488)\n- **High** — amber (#f59e0b)\n- **Urgent** — red (#dc2626)","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Backlog — Guided Tour",
            Slug = "backlog-walkthrough",
            Summary = "A guided tour of the backlog page: search, filters, table view, card view toggle, creating jobs, and opening job details.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/backlog"]""",
            Tags = """["backlog","walkthrough"]""",
            ContentJson = """{"appRoute":"/backlog","startButtonLabel":"Tour Backlog","steps":[{"element":".page-header app-input","popover":{"title":"Search Jobs","description":"Type here to search by job number or title. Results filter in real time as you type. Works in both table and card view.","side":"bottom"}},{"element":".page-header app-select:nth-of-type(1)","popover":{"title":"Track Type Filter","description":"Filter jobs by track type (e.g., Production, R&D/Tooling, Maintenance). When selected, only jobs whose current stage belongs to that track are shown. Set to 'All Tracks' to see everything.","side":"bottom"}},{"element":".page-header app-select:nth-of-type(2)","popover":{"title":"Priority Filter","description":"Filter by priority level: Low, Normal, High, or Urgent. Set to 'All Priorities' to show all jobs regardless of priority.","side":"bottom"}},{"element":".page-header app-select:nth-of-type(3)","popover":{"title":"Assignee Filter","description":"Filter to jobs assigned to a specific team member. The dropdown lists all users. Set to 'All Assignees' to remove the filter.","side":"bottom"}},{"element":".view-toggle","popover":{"title":"View Mode Toggle","description":"Switch between Table view (view_list icon) and Card view (view_module icon). Table view shows a sortable, filterable data table. Card view shows a grid of job cards with stage colors, priority dots, and assignee avatars. Your preference is saved automatically.","side":"bottom"}},{"element":".new-job-btn","popover":{"title":"Create Job","description":"Click to open the job creation dialog. You'll fill in a title (required), optional description, track type (required — determines which board the job enters), customer, assignee, priority, and due date. The job is created in the first stage of the selected track.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Jobs Table","description":"The main data table showing all filtered jobs. Columns: Job Number (80px), Title, Stage (color-coded chip), Priority (colored dot + label), Assignee (avatar), Customer, and Due Date. Click any column header to sort. Click the filter icon on filterable columns (Stage, Priority, Assignee, Customer, Due Date) for per-column filtering. Click any row to open the full job detail dialog.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Backlog Field Reference",
            Slug = "backlog-field-reference",
            Summary = "Complete reference for every field, column, filter, button, validation rule, row style, and view mode in the Backlog.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/backlog"]""",
            Tags = """["backlog","reference"]""",
            ContentJson = """{"title":"Backlog Field Reference","groups":[{"heading":"Page Header Filters","items":[{"label":"Search","value":"Free-text input. Filters jobs by title or job number. Case-insensitive, matches anywhere in the string. Results update in real time as you type."},{"label":"Track Type","value":"Select dropdown. Options: 'All Tracks' (default, shows all jobs) plus one option per configured track type (e.g., Production, R&D/Tooling, Maintenance). Filters by matching the job's current stage to the selected track's stage list."},{"label":"Priority","value":"Select dropdown. Options: 'All Priorities' (default), Low, Normal, High, Urgent. Filters to jobs matching the selected priority level."},{"label":"Assignee","value":"Select dropdown. Options: 'All Assignees' (default) plus one option per user (shown by name). Filters to jobs assigned to the selected user (matched by initials)."}]},{"heading":"View Mode Toggle","items":[{"label":"Table View button (view_list icon)","value":"Switches to the data table view. Active state shown by icon-btn--active class. This is the default view mode."},{"label":"Card View button (view_module icon)","value":"Switches to the card grid view. Active state shown by icon-btn--active class."},{"label":"View preference persistence","value":"View mode is saved to user preferences (key: backlog:viewMode) and synced to the URL via ?view=card query param. Table is the default — only card mode adds a query param. Preference is restored on next visit unless the URL explicitly specifies a view."}]},{"heading":"Job Create/Edit Dialog Fields","items":[{"label":"Title (required)","value":"Text input, max 200 characters. Validators: required, maxLength(200). data-testid: job-title. Shown on kanban cards, backlog table, and detail views."},{"label":"Description","value":"Textarea, 3 rows. Optional, no max length enforced in UI. data-testid: job-description. Provides additional context about the job scope."},{"label":"Track Type (create mode only)","value":"Select dropdown, required. Options loaded from API (configured track types). Validators: required. data-testid: job-track-type. Determines which kanban board and initial stage the job enters. Hidden in edit mode — track type cannot be changed after creation. To put a job on a different track, archive it and create a replacement on the correct track."},{"label":"Customer","value":"Select dropdown, optional. Options loaded from API (customer list) plus a null/'-- None --' option. data-testid: job-customer. Links job to a customer record."},{"label":"Assignee","value":"Select dropdown, optional. Options loaded from API (user list) plus a null/'-- None --' option. data-testid: job-assignee. If the selected user has an incomplete profile (missing required onboarding fields), a warning message is displayed below the field."},{"label":"Priority","value":"Select dropdown. Options: Low, Normal, High, Urgent. Default: Normal. data-testid: job-priority. Controls the priority dot color in table and card views."},{"label":"Due Date","value":"Datepicker, optional. data-testid: job-due-date. When set and the date has passed, the job is flagged as overdue (red text in table, highlighted card in grid)."},{"label":"Save button","value":"data-testid: job-save-btn. Disabled when form is invalid or saving is in progress. When the form is invalid, a red warning-triangle icon with an issue count appears to the left of the Save button; clicking it opens a popover listing the violations (e.g., 'Title is required', 'Track Type is required')."},{"label":"Cancel button","value":"Closes the dialog without saving. No confirmation unless the form has unsaved changes (dirty form guard)."}]},{"heading":"Table Columns","items":[{"label":"Job Number","value":"Width: 80px. Sortable, filterable (text). Rendered in monospace-styled span with class 'job-number'. Shows the auto-generated job number (e.g., J-1001)."},{"label":"Title","value":"Sortable, filterable (text). Rendered with class 'job-title'. The primary job name."},{"label":"Stage","value":"Width: 100px. Sortable, filterable (enum — options derived from current job data). Rendered as a colored chip with --chip-color set to the stage's configured color."},{"label":"Priority","value":"Width: 90px. Sortable, filterable (enum — Low/Normal/High/Urgent). Rendered as a colored dot (background color from PRIORITY_COLORS) followed by the priority name text."},{"label":"Assignee","value":"Width: 60px, center-aligned. Filterable (enum — options from user list by initials/name). Rendered as an app-avatar component (sm size) with the user's initials and color. Unassigned shows an em dash (—)."},{"label":"Customer Name","value":"Width: 120px. Sortable, filterable (enum — options derived from current job data, duplicates removed). Plain text, em dash (—) when no customer assigned."},{"label":"Due Date","value":"Width: 100px. Sortable, filterable (date). Formatted as MM/dd/yyyy via Angular DatePipe. Overdue dates rendered with class 'overdue-text' (red color)."}]},{"heading":"Row Styling (Table View)","items":[{"label":"row--overdue","value":"Applied when job.isOverdue is true (due date has passed). Adds a subtle red background tint to the entire row."},{"label":"row--selected","value":"Applied when the job's ID matches the currently selected job (detail dialog is open for this job). Highlights the row to indicate selection."},{"label":"--row-tint CSS variable","value":"Set to the job's stage color. Provides a faint background tint matching the stage color, giving a visual cue about which stage each job is in."}]},{"heading":"Card View Elements","items":[{"label":"Job Number","value":"Displayed in the card header with class 'backlog-card__number'."},{"label":"On Hold badge","value":"Warning chip shown in the card header when job.activeHolds.length > 0. Text: 'On Hold'."},{"label":"Title","value":"Card body text with class 'backlog-card__title'."},{"label":"Stage chip","value":"Color-coded chip with --chip-color set to job.stageColor. Shows the current stage name."},{"label":"Priority dot + name","value":"Colored dot (backlog-card__priority-dot) followed by priority name text. The dot color comes from the card grid's own priorityDotColor map (NOT the table's PRIORITY_COLORS) — its keys don't match the real priority names, so only Low and High resolve a color and Normal/Urgent fall back to gray. See the Advanced Reference for this known palette gap."},{"label":"Assignee avatar","value":"app-avatar (sm size) shown when job has an assignee. Omitted when unassigned."},{"label":"Customer","value":"Shown below the meta area with a business icon. Only rendered when job.customerName is present."},{"label":"Due Date","value":"Shown in the card footer with an event icon. Formatted as short date. Class 'backlog-card__date--overdue' applied when overdue (red). 'No date' text shown when no due date set."},{"label":"backlog-card--overdue","value":"Applied to the entire card when job.isOverdue is true. Visually highlights the card."},{"label":"backlog-card--selected","value":"Applied when this card's job ID matches the selected job. Highlights the card border/background."}]},{"heading":"Buttons and Actions","items":[{"label":"Create Job (page header)","value":"Button with + icon and text. Class: new-job-btn. Opens the job creation dialog in 'create' mode. No data-testid on this button (it's in the page header, not a dialog)."},{"label":"Row click (table)","value":"Clicking any table row opens the job detail dialog via DetailDialogService. URL updates to ?detail=job:{id}. The selected row gets row--selected styling."},{"label":"Card click (card view)","value":"Clicking any card opens the job detail dialog via DetailDialogService. URL updates to ?detail=job:{id}. The selected card gets backlog-card--selected styling."},{"label":"Detail dialog URL auto-open","value":"On page load, if the URL contains ?detail=job:{id}, the job detail dialog opens automatically. This supports direct links, bookmarks, and browser back/forward."},{"label":"Edit a job (entry point)","value":"There is no Edit button on the row or card. Open the job (click row/card) to show the detail dialog, then click its Edit action. The detail dialog closes returning {action:'edit'} and the backlog re-opens the same dialog in edit mode (title 'Edit Job', save button 'Save Changes'). In edit mode the Track Type select and the Sales Order line association are both hidden; Title, Description, Customer, Assignee, Priority, and Due Date remain editable."}]},{"heading":"Archived Jobs View (Admin only)","items":[{"label":"Show Archived / Show Active toggle","value":"Extra icon button in the page header, rendered only when the user has the Admin role. Icon: 'inventory' (active view) toggles to 'inventory_2' (archived view); tooltip + aria-label flip between 'Show archived jobs' and 'Show active jobs'; aria-pressed reflects state. Clicking flips showArchived() and re-fetches the list via getJobs({ isArchived: true/false }) — it is a server-side fetch of a separate job set, not a client filter. Switching also clears any current selection."},{"label":"Actions column (Unarchive)","value":"A trailing Actions column (90px, center-aligned) is added to the table only when showArchived() && isAdmin(). Each archived row gets an Unarchive icon button ('unarchive' icon, tooltip 'Unarchive'). Clicking it (event.stopPropagation so the row's detail dialog does NOT open) shows a confirm dialog ('Restore this job?', message names the job number); on confirm it POSTs /jobs/{id}/unarchive, shows a success snackbar, and reloads so the now-active job leaves the archived view."},{"label":"Row selection (archived view)","value":"The data table is [selectable] only when showArchived() && isAdmin(), adding a checkbox column. selectionChange feeds selectedJobs(); selectionCount() drives the bulk bar. Selection is cleared when toggling views or after a successful bulk action."},{"label":"Bulk action bar","value":"Appears (class bulk-bar, fixed at the bottom) only when showArchived() && isAdmin() && selectionCount() > 0. Shows '{n} selected', an 'Unarchive selected' button, and an X to clear the selection. The Unarchive selected button confirms ('Restore selected jobs?', count in message), then PATCHes /jobs/bulk/unarchive with the selected ids; a success snackbar reports how many were restored."},{"label":"Admin gating","value":"The toggle, Actions column, row selection, and bulk bar are all client-gated behind isAdmin(). The server independently enforces [Authorize(Roles = \"Admin\")] on the unarchive endpoints, so the recovery path is protected even if the client checks are bypassed."}]},{"heading":"Data Loading","items":[{"label":"Initial load","value":"Uses LoadingService.track() with forkJoin to load jobs, track types, and users simultaneously. Global loading overlay shown with message 'Loading backlog...'."},{"label":"Refresh after save","value":"After creating or editing a job via the dialog, the job list is reloaded from the API. The dialog closes and the updated data appears."},{"label":"Error state","value":"If the initial load fails, the page shows an error icon (error_outline) with a failure message instead of the table/card content."}]},{"heading":"Priority Colors","items":[{"label":"Low","value":"#94a3b8 (slate gray)"},{"label":"Normal","value":"#0d9488 (teal)"},{"label":"High","value":"#f59e0b (amber)"},{"label":"Urgent","value":"#dc2626 (red)"}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Backlog Knowledge Check",
            Slug = "backlog-quiz",
            Summary = "Test your knowledge of the Backlog module: filters, view modes, job creation, table columns, and card elements.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 7,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/backlog"]""",
            Tags = """["backlog","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"bl1","text":"What is the primary purpose of the Backlog page compared to the Kanban Board?","options":[{"id":"a","text":"The Backlog replaces the Kanban Board for teams that prefer list views"},{"id":"b","text":"The Backlog shows all jobs across every track type in a flat list for searching, filtering, and triaging work","isCorrect":true},{"id":"c","text":"The Backlog only shows jobs that haven't been assigned to a track yet"},{"id":"d","text":"The Backlog is a historical archive of completed jobs"}],"explanation":"The Backlog is a master list of all jobs across every track type. While the Kanban Board shows one track at a time organized by stage columns, the Backlog lets you see, search, and filter all jobs regardless of which track they belong to."},{"id":"bl2","text":"You want to find all urgent jobs assigned to a specific team member. What filters do you set?","options":[{"id":"a","text":"Set the Search field to the team member's name and the Priority filter to Urgent"},{"id":"b","text":"Set the Assignee filter to the team member and the Priority filter to Urgent","isCorrect":true},{"id":"c","text":"Set the Track Type filter and then sort the Priority column descending"},{"id":"d","text":"Use the Search field to type 'urgent' and scan the results visually"}],"explanation":"The Backlog has dedicated Assignee and Priority filters in the page header. Set Assignee to the team member's name and Priority to Urgent. These filters work together with AND logic, showing only jobs matching both criteria."},{"id":"bl3","text":"What happens when you switch from Table view to Card view?","options":[{"id":"a","text":"The URL updates to include ?view=card and the preference is saved for your next visit","isCorrect":true},{"id":"b","text":"Only the display changes — no URL or preference update occurs"},{"id":"c","text":"You are navigated to a completely different route (/backlog/cards)"},{"id":"d","text":"The card view opens in a new browser tab"}],"explanation":"The view mode is synced to the URL via the ?view=card query parameter and saved to user preferences (key: backlog:viewMode). Table view is the default and doesn't add a query param. Your choice persists across sessions."},{"id":"bl4","text":"In the job creation dialog, which fields are required?","options":[{"id":"a","text":"Title, Description, and Track Type"},{"id":"b","text":"Title and Track Type","isCorrect":true},{"id":"c","text":"Title, Track Type, Priority, and Customer"},{"id":"d","text":"Only Title is required — Track Type is auto-selected"}],"explanation":"The job creation dialog requires Title (max 200 characters) and Track Type. All other fields — Description, Customer, Assignee, Priority, and Due Date — are optional. Priority defaults to Normal if not changed."},{"id":"bl5","text":"What data-testid attribute identifies the job title input field in the create/edit dialog?","options":[{"id":"a","text":"data-testid=\"backlog-title\""},{"id":"b","text":"data-testid=\"job-title\"","isCorrect":true},{"id":"c","text":"data-testid=\"create-job-title\""},{"id":"d","text":"data-testid=\"title-input\""}],"explanation":"The job title input has data-testid=\"job-title\". All job dialog fields follow the pattern data-testid=\"job-{field}\": job-title, job-description, job-track-type, job-customer, job-assignee, job-priority, job-due-date, and job-save-btn."},{"id":"bl6","text":"A job row in the table has a red background tint. What does this indicate?","options":[{"id":"a","text":"The job has a critical priority level"},{"id":"b","text":"The job has an error and needs attention"},{"id":"c","text":"The job's due date has passed — it is overdue","isCorrect":true},{"id":"d","text":"The job is currently on hold"}],"explanation":"The row--overdue class is applied when job.isOverdue is true (the due date has passed). This adds a subtle red background tint to the entire row. Note: the faint stage color tint (--row-tint) is separate and always present."},{"id":"bl7","text":"What does the --row-tint CSS custom property control in the backlog table?","options":[{"id":"a","text":"It sets the text color of the job title to match the priority"},{"id":"b","text":"It provides a faint background tint matching the job's current stage color","isCorrect":true},{"id":"c","text":"It controls the border color on the left side of each row"},{"id":"d","text":"It highlights the row when the user hovers over it"}],"explanation":"The --row-tint CSS custom property is set to the job's stage color (job.stageColor) via the backlogRowStyle function. This gives each row a subtle background tint that visually indicates which stage the job is in, even without reading the Stage column."},{"id":"bl8","text":"When does the Track Type field appear in the job dialog?","options":[{"id":"a","text":"It always appears in both create and edit modes"},{"id":"b","text":"It only appears in create mode — track type cannot be changed after creation","isCorrect":true},{"id":"c","text":"It only appears in edit mode — create mode auto-assigns a default track"},{"id":"d","text":"It appears as a read-only display field in edit mode"}],"explanation":"The Track Type select (data-testid: job-track-type) is only shown in create mode. Once a job is created, its track type is permanent and determines which kanban board it belongs to. In edit mode, the field is hidden entirely."},{"id":"bl9","text":"How does the Backlog handle deep linking to a specific job's detail?","options":[{"id":"a","text":"Job IDs are stored in localStorage and restored on page load"},{"id":"b","text":"The URL includes ?detail=job:{id} which triggers the detail dialog to auto-open on page load","isCorrect":true},{"id":"c","text":"Deep linking is not supported — you must click a row to see details"},{"id":"d","text":"The job ID is stored in a route segment like /backlog/jobs/123"}],"explanation":"When you click a row or card, the URL updates to include ?detail=job:{id} via the DetailDialogService. On page load, if this query param is present, the detail dialog opens automatically. This makes links shareable and bookmarkable, and supports browser back/forward navigation."},{"id":"bl10","text":"What icon is used for the Card View toggle button?","options":[{"id":"a","text":"grid_view"},{"id":"b","text":"dashboard"},{"id":"c","text":"view_module","isCorrect":true},{"id":"d","text":"apps"}],"explanation":"The Card View toggle uses the view_module Material icon. The Table View toggle uses view_list. Both are in the page header's view-toggle group. The active button gets the icon-btn--active class."},{"id":"bl11","text":"In card view, what triggers the 'On Hold' badge to appear on a job card?","options":[{"id":"a","text":"The job's priority is set to Urgent"},{"id":"b","text":"The job has been in the same stage for more than 7 days"},{"id":"c","text":"The job has one or more active holds (job.activeHolds.length > 0)","isCorrect":true},{"id":"d","text":"The job's assignee has not logged in recently"}],"explanation":"The 'On Hold' badge (a warning-colored chip) appears in the card header when job.activeHolds.length > 0. Holds are managed through the job detail dialog's status lifecycle features and indicate the job is blocked or paused."},{"id":"bl12","text":"What color represents a 'High' priority job's dot in the backlog?","options":[{"id":"a","text":"Red (#dc2626)"},{"id":"b","text":"Teal (#0d9488)"},{"id":"c","text":"Amber (#f59e0b)","isCorrect":true},{"id":"d","text":"Slate gray (#94a3b8)"}],"explanation":"Priority colors are: Low = #94a3b8 (slate gray), Normal = #0d9488 (teal), High = #f59e0b (amber), Urgent = #dc2626 (red). These canonical colors are defined in the PRIORITY_COLORS constant used by the table dot. (The card view resolves dot colors through a separate, non-matching map — see the Advanced Reference for that palette gap.)"},{"id":"bl13","text":"How are validation errors surfaced when the Save button is disabled in the job creation dialog?","options":[{"id":"a","text":"Nothing — the button is grayed out with no additional feedback"},{"id":"b","text":"A tooltip says 'Please fill in all required fields'"},{"id":"c","text":"A red warning-triangle icon with an issue count sits to the left of the Save button; clicking it opens a popover listing the errors (e.g., 'Title is required')","isCorrect":true},{"id":"d","text":"The invalid fields flash red to draw attention"}],"explanation":"The Save button is wrapped in the <app-validation-button> stereotype (ValidationButtonComponent). When the form is invalid, a red warning-triangle icon with a count of issues appears to the left of the still-disabled Save button. Clicking that icon opens a popover listing the violations, such as 'Title is required' or 'Track Type is required'. This is the standard Forge form-validation pattern — no inline mat-error messages, and it is click-to-reveal rather than a hover tooltip."},{"id":"bl14","text":"How does the Track Type filter work in the Backlog?","options":[{"id":"a","text":"It hides all jobs except those whose job.trackTypeId matches the selected track"},{"id":"b","text":"It filters jobs by matching the job's current stage name against the selected track type's stage list","isCorrect":true},{"id":"c","text":"It groups the table rows by track type, collapsing non-selected tracks"},{"id":"d","text":"It navigates you to the Kanban Board for the selected track"}],"explanation":"The Track Type filter looks up the selected track's stages, builds a Set of stage names, and filters jobs to only those whose current stageName is in that set. This means if a job is in a stage that belongs to the selected track, it appears — the filter works through stage membership, not a direct trackTypeId on the job."},{"id":"bl15","text":"What data-testid would you use to locate the due date picker in the job creation dialog?","options":[{"id":"a","text":"data-testid=\"job-dueDate\""},{"id":"b","text":"data-testid=\"job-due-date\"","isCorrect":true},{"id":"c","text":"data-testid=\"backlog-due-date\""},{"id":"d","text":"data-testid=\"create-due-date\""}],"explanation":"The due date picker has data-testid=\"job-due-date\". The job dialog uses the naming convention data-testid=\"job-{field-name}\" with kebab-case field names: job-title, job-description, job-track-type, job-customer, job-assignee, job-priority, job-due-date, and job-save-btn."},{"id":"bl16","text":"You are an admin and want to review jobs that were archived off the board. How do you get to them from the Backlog?","options":[{"id":"a","text":"Set the Track Type filter to 'Archived'"},{"id":"b","text":"Click the inventory-box toggle button in the page header to switch from active to archived jobs","isCorrect":true},{"id":"c","text":"Type 'archived' into the Search field"},{"id":"d","text":"Archived jobs cannot be viewed — they are permanently deleted"}],"explanation":"Admins get an extra icon button (an inventory-box icon) in the page header. Clicking it flips the Show Archived / Show Active toggle and re-fetches the list from the server with the archived flag set — a separate set of jobs, not a client-side filter. Non-admins never see this toggle. Jobs are archived (soft-deleted), never hard-deleted, so they remain fully recoverable."},{"id":"bl17","text":"In the admin archived view, how do you restore several jobs to the active list at once?","options":[{"id":"a","text":"Select the archived rows with their checkboxes, then click 'Unarchive selected' in the bulk action bar and confirm","isCorrect":true},{"id":"b","text":"There is no bulk option — you must unarchive each job one row at a time"},{"id":"c","text":"Drag the selected jobs back onto the Kanban board"},{"id":"d","text":"Change each job's status to 'Active' in the create dialog"}],"explanation":"In the archived view the table becomes selectable (a checkbox per row). Selecting one or more jobs raises a bulk action bar at the bottom showing the count and an 'Unarchive selected' button. After you confirm 'Restore selected jobs?', all selected jobs are restored in one operation (PATCH /jobs/bulk/unarchive) and a success message reports how many were restored. A single-row Unarchive button in the Actions column handles the one-at-a-time case."},{"id":"bl18","text":"You open a job and need to change its track type from Production to Maintenance. What does the UI let you do?","options":[{"id":"a","text":"Open the job's detail dialog, click Edit, and pick a new Track Type from the dropdown"},{"id":"b","text":"Nothing — track type is immutable; the Track Type field is hidden in edit mode, so you archive the job and create a replacement on the correct track","isCorrect":true},{"id":"c","text":"Drag the job to the Maintenance board, which reassigns its track type"},{"id":"d","text":"Track type changes automatically based on the assignee's team"}],"explanation":"To edit a job you open it (click the row/card), then use the detail dialog's Edit action, which re-opens the job in the create/edit dialog in edit mode. In edit mode the Track Type field is hidden entirely — a job's track type is fixed at creation because it determines which Kanban board the job lives on. To move a job to a different track, archive it and create a replacement on the correct track."}]}"""
        });

        // ── Advanced Reference (Reference) ───────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Backlog — Advanced Reference",
            Slug = "backlog-reference",
            Summary = "Edge-case and power-user notes: assignee profile gating, view-mode persistence, the card-vs-table priority palette gap, the 200-job fetch cap, and empty/error states.",
            ContentType = TrainingContentType.Reference,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 90,
            AppRoutes = """["/backlog"]""",
            Tags = """["backlog","reference","advanced"]""",
            ContentJson = """{"body":"## Assignee incomplete-profile warning\n\nThe Assignee dropdown in the job create/edit dialog (`job-assignee`) does not block selecting a user with an unfinished onboarding profile — it flags them. Each user carries a `canBeAssignedJobs` boolean; when it is `false`, that user's option label is decorated with a leading `⚠` and a trailing `(incomplete profile)` suffix instead of a plain name. The flag is server-computed by `GetProfileCompleteness`: `CanBeAssignedJobs` is true only when every onboarding item marked `BlocksJobAssignment` is complete. The four blocking items are **W-4** (`W4CompletedAt`), **I-9** (`I9CompletedAt`), **State Tax Withholding** (`StateWithholdingCompletedAt`, auto-satisfied in no-income-tax states), and **Emergency Contact** (name + phone). Non-blocking items (Home Address, Direct Deposit, Workers' Comp, Handbook) can be missing and the user is still assignable. The warning is advisory only — you can still assign the job; nothing in the dialog prevents save.\n\n## View-mode persistence internals\n\nView mode is `'table' | 'card'`, and the **URL is the source of truth**: `viewMode` is a `toSignal` over the `?view=` query param, defaulting to `table`. Table is the implied default and never writes a param — `setViewMode('table')` sets `view: null` (removing it), while `setViewMode('card')` sets `view=card`. Every `setViewMode` call also writes the choice to `UserPreferencesService` under the key `backlog:viewMode`. On construction the component reads the saved preference and, only if it is `'card'` AND the URL has no explicit `view` param, navigates to `{ view: 'card' }` with `replaceUrl: true` so the restore does not add a history entry. Net effect: an explicit `?view=` in the link always wins over the saved preference; otherwise your last-used mode is restored. There is no server round-trip for the mode itself — the preference write is the localStorage-backed `UserPreferencesService`.\n\n## Card-grid vs. table priority palette inconsistency\n\nThe two views resolve the priority-dot color through **different, non-matching maps** — a known wart. The table (and the field reference) use the shared `PRIORITY_COLORS` constant keyed to the real `PRIORITIES` enum (`Low #94a3b8`, `Normal #0d9488`, `High #f59e0b`, `Urgent #dc2626`). The card grid's `BacklogCardGridComponent.priorityDotColor()` instead hardcodes a separate map keyed `Critical #dc2626`, `High #f97316`, `Medium #d97706`, `Low #22c55e`, with a `#94a3b8` fallback. Because the card map's keys do not align with the actual priority names, only `Low` and `High` resolve a color in card view — and even `High` resolves to a different orange (`#f97316` vs the table's amber `#f59e0b`). `Normal` and `Urgent` have no card-map entry and fall through to the gray fallback `#94a3b8`. So the same job can show one dot color in the table and a different color (or gray) on its card. Treat the table palette as canonical; the card colors are not authoritative.\n\n## 200-job fetch cap\n\nThe backlog is **not** server-paginated. `BacklogService.getJobs()` calls `GET /jobs` with `pageSize=200` (plus `isArchived`, and optional `trackTypeId` / `assigneeId` / `search`) and unwraps the paged envelope to `p.items`. 200 is the server's max page size, so the backlog shows at most the first 200 active (or archived) jobs; anything beyond that is silently omitted. All filtering, sorting, and the search box operate **client-side** over that already-fetched set (`filteredJobs` is a computed signal), not against the server. The inline code comment flags the ceiling explicitly: switch to true server-paging if a backlog grows past 200. For installs near that size, lean on the Track Type / Assignee filters (or the Kanban board per-track) rather than expecting the flat list to show everything.\n\n## Empty and load-error states\n\nThree distinct states render depending on what failed:\n\n- **Load error** — if the initial `forkJoin` (jobs + track types + users) errors, the `error` signal is set to `backlog.loadFailed` (\"Failed to load backlog\") and the template short-circuits to a `page-error` block (an `error_outline` icon + the message) **instead of** the page header and content. The filters and table never render.\n- **Empty in table view** — when the load succeeds but `filteredJobs()` is empty, `app-data-table` shows its built-in empty state: the `search_off` icon, `backlog.noJobsMatch` (\"No jobs match your filters\"), and help text `backlog.noJobsHelp` (\"Try adjusting your search or filters. Jobs are added from the Board page.\").\n- **Empty in card view** — `BacklogCardGridComponent` renders its own empty block: a `search_off` icon and the hardcoded string \"No jobs match your filters\" (this card-grid string is not wired through i18n the way the table's keys are).\n\nThe card view is also wrapped in a `LoadingBlockDirective` (`[appLoadingBlock]=\"isLoading()\"`) for a section-level spinner, whereas the initial aggregate load uses the global `LoadingService.track('Loading backlog...')` overlay.","sections":[]}"""
        });

        Log.Information("Seeded Backlog training modules");
    }
